export async function main(args: string[]) {
  const parsed = parseArgs(args);

  if (parsed.help) { printHelp(); return; }
  if (parsed.export) { handleExport(parsed); return; }

  // Shared setup
  const { agent, sessionManager, settingsManager } = await setupAgent(parsed);
  const session = new AgentSession(agent, sessionManager, settingsManager);

  // Route to mode
  if (parsed.mode === "rpc") {
    await runRpcMode(session);
  } else if (parsed.print || parsed.mode) {
