## How Modes Would Use It

### Print Mode (simplest)

```typescript
// src/modes/print-mode.ts

export async function runPrintMode(
  session: AgentSession,
  mode: "text" | "json",
  messages: string[],
  initialMessage?: string,
  initialAttachments?: Attachment[],
): Promise<void> {

  if (mode === "json") {
    // Just pipe events to stdout
    session.subscribe((event) => {
      console.log(JSON.stringify(event));
    });
  }

  // Send messages
  if (initialMessage) {
    await session.prompt(initialMessage, { attachments: initialAttachments });
  }
  for (const message of messages) {
    await session.prompt(message);
  }

  // In text mode, output final response
  if (mode === "text") {
    const lastText = session.getLastAssistantText();
    if (lastText) {
      console.log(lastText);
    }
  }
}
```

### RPC Mode

```typescript
// src/modes/rpc-mode.ts

export async function runRpcMode(session: AgentSession): Promise<never> {
  // Pipe all events to stdout as JSON
  session.subscribe((event) => {
    console.log(JSON.stringify(event));
  });

  // Listen for JSON input
  const rl = readline.createInterface({ input: process.stdin });

  rl.on("line", async (line: string) => {
    try {
      const input = JSON.parse(line);

      switch (input.type) {
        case "prompt":
          await session.prompt(input.message, { attachments: input.attachments });
          break;

        case "abort":
          await session.abort();
          break;

        case "compact":
          const result = await session.compact(input.customInstructions);
          console.log(JSON.stringify({ type: "compaction", ...result }));
          break;

        case "bash":
          const bashResult = await session.executeBash(input.command);
          console.log(JSON.stringify({ type: "bash_end", ...bashResult }));
          break;

        case "setModel":
          // Could add model switching via RPC
          break;

        case "setThinking":
          session.setThinkingLevel(input.level);
          break;
      }
    } catch (error: any) {
      console.log(JSON.stringify({ type: "error", error: error.message }));
    }
  });

  return new Promise(() => {}); // Never resolves
}
```

### Interactive Mode (most complex, but cleaner)

```typescript
// src/modes/interactive-mode.ts

export class InteractiveMode {
  private session: AgentSession;
  private tui: TUI;
  private components: TuiComponents;  // Chat container, editor, footer, etc.

  constructor(session: AgentSession, options: InteractiveModeOptions) {
    this.session = session;
    this.tui = new TUI(new ProcessTerminal());
    this.components = this.createComponents();

    // Subscribe to session events for rendering
    session.subscribe((event) => this.handleEvent(event));
  }

  async run(): Promise<void> {
    await this.init();

    while (true) {
      const input = await this.getEditorInput();
      await this.handleInput(input);
    }
  }

  private async handleInput(text: string): Promise<void> {
    // Slash commands
    if (text === "/thinking") {
      this.showThinkingSelector();
      return;
    }
    if (text === "/model") {
      this.showModelSelector();
      return;
    }
    if (text === "/compact") {
      await this.handleCompact();
      return;
    }
    if (text === "/copy") {
      this.handleCopy();
      return;
    }
    // ... other commands

    // Bash command
    if (text.startsWith("!")) {
      await this.handleBash(text.slice(1));
      return;
    }

    // Regular prompt
    try {
      await this.session.prompt(text);
    } catch (error) {
      this.showError(error.message);
    }
  }

  // ─── Slash Command Handlers ───

  private async handleCompact(): Promise<void> {
    this.showLoader("Compacting...");
    try {
      const result = await this.session.compact();
      this.rebuildChat();
      this.addCompactionComponent(result);
    } catch (error) {
      this.showError(`Compaction failed: ${error.message}`);
    } finally {
      this.hideLoader();
    }
  }

  private handleCopy(): void {
    const text = this.session.getLastAssistantText();
    if (!text) {
      this.showError("No assistant message to copy");
      return;
    }
    copyToClipboard(text);
    this.showMessage("Copied to clipboard");
  }

  private async handleBash(command: string): Promise<void> {
    const component = new BashExecutionComponent(command);
    this.components.chat.addChild(component);

    const result = await this.session.executeBash(command, (chunk) => {
      component.appendOutput(chunk);
      this.tui.requestRender();
    });

    component.setComplete(result);
    this.tui.requestRender();
  }

  // ─── Hotkey Handlers ───

  private handleEscape(): void {
    if (this.session.isStreaming) {
      // Restore queued messages to editor
      const queued = this.session.clearQueue();
      const current = this.components.editor.getText();
      this.components.editor.setText([...queued, current].filter(Boolean).join("\n\n"));
      this.session.abort();
    } else if (this.session.isBashRunning) {
      this.session.abortBash();
    }
  }

  private handleShiftTab(): void {
    const newLevel = this.session.cycleThinkingLevel();
    if (newLevel === null) {
      this.showMessage("Model doesn't support thinking");
    } else {
      this.showMessage(`Thinking: ${newLevel}`);
      this.updateEditorBorder();
    }
  }

  private async handleCtrlP(): Promise<void> {
    const result = await this.session.cycleModel();
    if (result === null) {
      this.showMessage("Only one model available");
    } else {
      const thinkingStr = result.thinkingLevel !== "off" ? ` (thinking: ${result.thinkingLevel})` : "";
      this.showMessage(`Switched to ${result.model.name || result.model.id}${thinkingStr}`);
      this.updateEditorBorder();
    }
  }

  // ─── Event Handling (just rendering) ───

  private handleEvent(event: AgentEvent): void {
    // Pure rendering logic - no session management
    switch (event.type) {
      case "agent_start":
        this.showLoader("Working...");
        break;
      case "message_start":
        if (event.message.role === "user") {
          this.addUserMessage(event.message);
        } else {
          this.startStreamingAssistant();
        }
        break;
      case "message_update":
        this.updateStreamingAssistant(event.message);
        break;
      case "message_end":
        this.finalizeMessage(event.message);
        break;
      case "agent_end":
        this.hideLoader();
        break;
    }
    this.tui.requestRender();
  }
}
```

## What This Achieves

### 1. **Single Source of Truth**
All agent/session logic lives in `AgentSession`:
- No more duplicate `checkAutoCompaction()` 
- No more duplicate bash execution
- No more duplicate session saving
- Model/thinking changes always go through one path

### 2. **Clear Separation**
- `AgentSession` = state management, persistence, business logic
- Modes = I/O and presentation

### 3. **Testable**
```typescript
// Can unit test AgentSession without any TUI
const session = new AgentSession({ agent, sessionManager, settingsManager });
await session.setThinkingLevel("high");
expect(session.thinkingLevel).toBe("high");
expect(settingsManager.getDefaultThinkingLevel()).toBe("high");
```

### 4. **Extensible**
Adding a new mode (e.g., LSP server mode, web socket mode) just means:
1. Create `AgentSession`
2. Subscribe to events
3. Implement your I/O layer

### 5. **Reduced main.ts**
Model resolution, thinking restoration, session loading can all be helper functions or part of an `AgentSession.create()` factory:

```typescript
// main.ts
const session = await AgentSession.create({
  args: parsed,
  settingsManager,
  sessionManager,
});

if (mode === "rpc") await runRpcMode(session);
else if (mode === "print") await runPrintMode(session, ...);
else await runInteractiveMode(session, ...);
```

