      const scopedModels = [
        { model: modelA, thinkingLevel: "high" },
        { model: modelB, thinkingLevel: "off" },
      ];
      session = new AgentSession({ ..., scopedModels });

      const result = await session.cycleModel();
      expect(result.model).toBe(modelB);
      expect(result.thinkingLevel).toBe("off");
    });
  });

  describe("bash execution", () => {
    it("adds result to agent context", async () => {
      const result = await session.executeBash("echo hello");
      expect(mockAgent.appendMessage).toHaveBeenCalledWith(
        expect.objectContaining({ role: "bashExecution", command: "echo hello" })
      );
    });

    it("can be aborted", async () => {
      const promise = session.executeBash("sleep 10");
      session.abortBash();
      const result = await promise;
      expect(result.cancelled).toBe(true);
    });
  });
});
